import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Artist {
  name: string;
  hours: number;
}

interface Genre {
  genre: string;
  hours: number;
}

interface MusicData {
  listeningSummary: {
    totalHours: number;
    averageDailyHours: number;
  };
  topArtists: Artist[];
  topGenres: Genre[];
}

export default function Widget() {
  const musicData = response.data as MusicData;
  const { listeningSummary, topArtists, topGenres } = musicData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Music Insights
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Listening Hours
            </Typography>
            <Typography variant="h4" fontWeight={700}>
              {listeningSummary.totalHours} Hours
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Avg Daily: {listeningSummary.averageDailyHours} Hours
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1 }}>
              Top Artists
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {topArtists.map((artist, index) => (
                <Chip key={index} label={`${artist.name} (${artist.hours}h)`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#333', color: '#FEE440' }} />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1 }}>
              Top Genres
            </Typography>
            <PieChart
              height={160}
              series={[
                {
                  data: topGenres.map((genre) => ({ key: genre.genre, data: genre.hours })),
                  color: ['#1DB954', '#FEE440', '#8B5CF6'],
                },
              ]}
              labels={({ datum }) => `${datum.key}`}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
